svg.script:

function zeige_kreis_farbe() {
  alert(document.getElementById("kreis").getAttributeNS(null,"fill"));
}

function zeige_kreis_umfang(evt) {
  var r = parseFloat(evt.target.getAttributeNS(null,"r"));
  alert("Der Kreisumfang ist ca.: " + (2*r*3.14));
}

function zeige_anzahl_kindelemente() {
  alert("Anzahl Kindelelemente: "+document.documentElement.childNodes.length);
}
